#include <iostream>
#include <vector>

void initializeWithDefaults(int* arr, int size);

void printArray(const int* arr, int size) {
    std::cout << "[";
    if (arr == nullptr) {
        std::cout << "nullptr (no elements)";
    } else {
        for (int i = 0; i < size; ++i) {
            std::cout << arr[i] << (i == size - 1 ? "" : ",");
        }
    }
    std::cout << "]";
}

int main() {
    // Test Case 1: Normal array
    {
        int size = 5;
        int* arr = new int[size];
        for (int i = 0; i < size; ++i) arr[i] = i + 1; 
        std::cout << "Test Case 1: Input array: ";
        printArray(arr, size);
        std::cout << ", size=" << size << std::endl;
        initializeWithDefaults(arr, size);
        std::cout << "Expected: [-1,-1,-1,-1,-1], Actual: ";
        printArray(arr, size);
        std::cout << std::endl << std::endl;
        delete[] arr;
    }

    // Test Case 2: Empty array
    {
        int size = 0;
        int* arr = new int[size]; 
        std::cout << "Test Case 2: Input array: ";
        printArray(arr, size);
        std::cout << ", size=" << size << std::endl;
        initializeWithDefaults(arr, size);
        std::cout << "Expected: [], Actual: ";
        printArray(arr, size);
        std::cout << std::endl << std::endl;
        delete[] arr;
    }

    // Test Case 3: Single element array
    {
        int size = 1;
        int* arr = new int[size];
        arr[0] = 100;
        std::cout << "Test Case 3: Input array: ";
        printArray(arr, size);
        std::cout << ", size=" << size << std::endl;
        initializeWithDefaults(arr, size);
        std::cout << "Expected: [-1], Actual: ";
        printArray(arr, size);
        std::cout << std::endl << std::endl;
        delete[] arr;
    }

    // Test Case 4: nullptr array (robustness check)
    {
        int size = 3;
        int* arr = nullptr; 
        std::cout << "Test Case 4: Input array: nullptr, size=" << size << std::endl;
        initializeWithDefaults(arr, size);
        std::cout << "Expected: [] (no change to non-existent array), Actual: [] (no change)";
        std::cout << std::endl << std::endl;
    }

    // Test Case 5: Negative size (should also be handled gracefully)
    {
        int size = -5;
        int arr_val[] = {1, 2, 3}; // Original content for comparison
        int* arr = new int[3];
        for(int i=0; i<3; ++i) arr[i] = arr_val[i];

        std::cout << "Test Case 5: Input array: ";
        printArray(arr, 3);
        std::cout << ", size=" << size << std::endl;
        initializeWithDefaults(arr, size);
        std::cout << "Expected: [1,2,3] (no change), Actual: ";
        printArray(arr, 3);
        std::cout << std::endl << std::endl;
        delete[] arr;
    }

    return 0;
}
